import React, { useEffect, useState } from 'react';
import { Animated, StyleSheet, Text, View, TouchableOpacity } from 'react-native';
import Icon from '@expo/vector-icons/MaterialIcons';
import { useTheme } from '../store/ThemeContext';
import { useSafeAreaInsets } from 'react-native-safe-area-context';

export type ToastType = 'success' | 'error' | 'info' | 'warning';

interface ToastProps {
  visible: boolean;
  message: string;
  type: ToastType;
  onHide: () => void;
}

export const Toast = ({ visible, message, type, onHide }: ToastProps) => {
  const { colors, isDark } = useTheme();
  const insets = useSafeAreaInsets();
  const [translateY] = useState(() => new Animated.Value(-100));
  const [opacity] = useState(() => new Animated.Value(0));

  useEffect(() => {
    if (visible) {
      Animated.parallel([
        Animated.spring(translateY, {
          toValue: insets.top + 10,
          useNativeDriver: true,
          tension: 80,
          friction: 10,
        }),
        Animated.timing(opacity, {
          toValue: 1,
          duration: 300,
          useNativeDriver: true,
        }),
      ]).start();
    } else {
      Animated.parallel([
        Animated.timing(translateY, {
          toValue: -100,
          duration: 300,
          useNativeDriver: true,
        }),
        Animated.timing(opacity, {
          toValue: 0,
          duration: 300,
          useNativeDriver: true,
        }),
      ]).start();
    }
  }, [visible, insets.top, translateY, opacity]);

  const getBackgroundColor = () => {
    switch (type) {
      case 'success':
        return colors.success;
      case 'error':
        return colors.danger;
      case 'warning':
        return '#f59e0b'; // Amber 500
      default:
        return colors.primary;
    }
  };

  const getIcon = () => {
    switch (type) {
      case 'success':
        return 'check-circle';
      case 'error':
        return 'error-outline';
      case 'warning':
        return 'warning-amber';
      default:
        return 'info-outline';
    }
  };

  if (!visible) return null;

  return (
    <Animated.View
      style={[
        styles.container,
        {
          transform: [{ translateY }],
          opacity,
          backgroundColor: isDark ? '#1e1e1e' : '#fff',
          shadowColor: '#000',
          borderColor: getBackgroundColor() + '40',
        },
      ]}
    >
      <View style={[styles.content, { backgroundColor: getBackgroundColor() + '10' }]}>
        <View style={[styles.iconContainer, { backgroundColor: getBackgroundColor() }]}>
          <Icon name={getIcon()} size={20} color="#fff" />
        </View>
        <Text style={[styles.message, { color: isDark ? '#fff' : '#333' }]} numberOfLines={2}>
          {message}
        </Text>
        <TouchableOpacity onPress={onHide} style={styles.closeBtn}>
          <Icon name="close" size={18} color={isDark ? '#aaa' : '#999'} />
        </TouchableOpacity>
      </View>
    </Animated.View>
  );
};

const styles = StyleSheet.create({
  container: {
    position: 'absolute',
    top: 0,
    left: 20,
    right: 20,
    zIndex: 9999,
    borderRadius: 16,
    borderWidth: 1,
    elevation: 8,
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.15,
    shadowRadius: 10,
    overflow: 'hidden',
  },
  content: {
    flexDirection: 'row',
    alignItems: 'center',
    padding: 12,
    paddingRight: 8,
  },
  iconContainer: {
    width: 32,
    height: 32,
    borderRadius: 10,
    justifyContent: 'center',
    alignItems: 'center',
    marginRight: 12,
  },
  message: {
    flex: 1,
    fontSize: 14,
    fontWeight: '600',
    lineHeight: 18,
  },
  closeBtn: {
    padding: 8,
  },
});

import React, { useState, useEffect } from 'react';
import { View, Text, TextInput, TouchableOpacity, ScrollView, StyleSheet } from 'react-native';
import { BottomSheet } from '../BottomSheet';
import { useTheme } from '../../store/ThemeContext';
import { useAuth } from '../../store/AuthContext';
import { Budget, Category } from '../../models/types';
import MaterialIcons from '@expo/vector-icons/MaterialIcons';
import { format } from 'date-fns';
import { common } from '../../styles/common';

interface BudgetForm {
  name: string;
  amount: string;
  interval: string;
  categories: string[];
  logo: string;
}

interface BudgetAddEditModalProps {
  visible: boolean;
  onClose: () => void;
  editingBudget: Budget | null;
  allCategories: Category[];
  onSave: (budgetData: Omit<Budget, 'id'>) => Promise<void>;
  onDeleteRequest?: (id: string) => void;
}

export const BudgetAddEditModal: React.FC<BudgetAddEditModalProps> = ({
  visible,
  onClose,
  editingBudget,
  allCategories,
  onSave,
  onDeleteRequest,
}) => {
  const { colors } = useTheme();
  const { session } = useAuth();
  const [form, setForm] = useState<BudgetForm>({
    name: '',
    amount: '',
    interval: 'Monthly',
    categories: [],
    logo: 'account-balance-wallet',
  });

  useEffect(() => {
    if (visible) {
      const timer = setTimeout(() => {
        if (editingBudget) {
          setForm({
            name: editingBudget.name,
            amount: editingBudget.amount.toString(),
            interval: editingBudget.interval,
            categories: JSON.parse(editingBudget.categories),
            logo: editingBudget.logo,
          });
        } else {
          setForm({
            name: '',
            amount: '',
            interval: 'Monthly',
            categories: [],
            logo: 'account-balance-wallet',
          });
        }
      }, 0);
      return () => clearTimeout(timer);
    }
  }, [visible, editingBudget]);

  const handleSave = () => {
    const budgetData = {
      user_id: session?.user?.id || '',
      name: form.name,
      amount: parseFloat(form.amount) || 0,
      categories: JSON.stringify(form.categories),
      interval: form.interval,
      logo: form.logo,
      start_date: editingBudget?.start_date || format(new Date(), 'yyyy-MM-dd'),
    };
    onSave(budgetData);
  };

  return (
    <BottomSheet
      visible={visible}
      onClose={onClose}
      title={editingBudget ? 'Edit Budget' : 'New Budget'}
      headerRight={
        editingBudget && onDeleteRequest ? (
          <TouchableOpacity
            onPress={() => onDeleteRequest(editingBudget.id)}
            style={styles.deleteBtnIcon}
          >
            <MaterialIcons name="delete" size={24} color={colors.danger} />
          </TouchableOpacity>
        ) : undefined
      }
    >
      <View>
        <ScrollView showsVerticalScrollIndicator={false} style={styles.scrollContainer}>
          <View style={styles.inputGroup}>
            <Text style={[styles.label, { color: colors.textSecondary }]}>BUDGET NAME</Text>
            <TextInput
              style={[styles.input, { color: colors.text, borderBottomColor: colors.border }]}
              value={form.name}
              onChangeText={(t) => setForm((f) => ({ ...f, name: t }))}
              placeholder="e.g. Monthly Grocery"
              placeholderTextColor={colors.textSecondary + '80'}
            />
          </View>

          <View style={styles.inputGroup}>
            <Text style={[styles.label, { color: colors.textSecondary }]}>MONTHLY AMOUNT</Text>
            <TextInput
              style={[styles.input, { color: colors.text, borderBottomColor: colors.border }]}
              value={form.amount}
              onChangeText={(t) => setForm((f) => ({ ...f, amount: t }))}
              placeholder="0.00"
              placeholderTextColor={colors.textSecondary + '80'}
              keyboardType="numeric"
            />
          </View>

          <View style={styles.inputGroup}>
            <Text style={[styles.label, { color: colors.textSecondary }]}>CATEGORIES</Text>
            <View style={styles.categoryGrid}>
              {allCategories.map((cat) => {
                const isSelected = form.categories.includes(cat.id);
                return (
                  <TouchableOpacity
                    key={cat.id}
                    onPress={() => {
                      const newCats = isSelected
                        ? form.categories.filter((id) => id !== cat.id)
                        : [...form.categories, cat.id];
                      setForm((f) => ({ ...f, categories: newCats }));
                    }}
                    style={[
                      styles.catChip,
                      isSelected
                        ? styles.catChipActive
                        : { backgroundColor: colors.background, borderColor: colors.border },
                    ]}
                  >
                    <Text
                      style={[
                        styles.catChipText,
                        { color: isSelected ? '#fff' : colors.textSecondary },
                      ]}
                    >
                      {cat.name}
                    </Text>
                  </TouchableOpacity>
                );
              })}
            </View>
          </View>
        </ScrollView>

        <TouchableOpacity
          style={[styles.saveBtn, { backgroundColor: colors.primary }]}
          onPress={handleSave}
        >
          <Text style={styles.saveBtnText}>Save Budget</Text>
        </TouchableOpacity>
        <View style={common.h40} />
      </View>
    </BottomSheet>
  );
};
BudgetAddEditModal.displayName = 'BudgetAddEditModal';

const styles = StyleSheet.create({
  deleteBtnIcon: {
    padding: 10,
  },
  inputGroup: {
    marginBottom: 20,
  },
  label: {
    fontSize: 11,
    fontWeight: '800',
    marginBottom: 8,
    letterSpacing: 1,
  },
  input: {
    fontSize: 17,
    fontWeight: '600',
    borderBottomWidth: 1,
    paddingVertical: 12,
  },
  categoryGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 10,
    marginTop: 8,
  },
  catChip: {
    paddingHorizontal: 12,
    paddingVertical: 8,
    borderRadius: 20,
    borderWidth: 1,
  },
  catChipText: {
    fontSize: 13,
    fontWeight: '600',
  },
  saveBtn: {
    paddingVertical: 16,
    borderRadius: 16,
    alignItems: 'center',
    marginTop: 16,
  },
  saveBtnText: {
    color: '#fff',
    fontSize: 16,
    fontWeight: '700',
  },
  scrollContainer: {
    maxHeight: 500,
  },
  catChipActive: {
    backgroundColor: '#3b82f6', // primary
    borderColor: '#3b82f6',
  },
});

import React from 'react';
import { View, Text, FlatList, ActivityIndicator, StyleSheet } from 'react-native';
import { BottomSheet } from '../BottomSheet';
import { TransactionCard } from '../TransactionCard';
import { useTheme } from '../../store/ThemeContext';
import { Transaction } from '../../models/types';
import MaterialIcons from '@expo/vector-icons/MaterialIcons';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { common } from '../../styles/common';

interface BudgetDrillDownModalProps {
  visible: boolean;
  onClose: () => void;
  title: string;
  subtitle: string;
  loading: boolean;
  transactions: Transaction[];
}

export const BudgetDrillDownModal: React.FC<BudgetDrillDownModalProps> = ({
  visible,
  onClose,
  title,
  subtitle,
  loading,
  transactions,
}) => {
  const { colors } = useTheme();
  const insets = useSafeAreaInsets();

  return (
    <BottomSheet visible={visible} onClose={onClose} title={title} subtitle={subtitle} isFullScreen>
      <View style={common.flex1}>
        {loading ? (
          <ActivityIndicator size="large" color={colors.primary} style={common.mt40} />
        ) : (
          <FlatList
            data={transactions}
            keyExtractor={(item) => item.id}
            renderItem={({ item }) => <TransactionCard transaction={item} />}
            contentContainerStyle={{ paddingBottom: insets.bottom + 40 }}
            ListEmptyComponent={
              <View style={styles.emptyDrill}>
                <MaterialIcons name="search-off" size={64} color={colors.border} />
                <Text style={[styles.emptyText, { color: colors.textSecondary }]}>
                  No transactions found for this budget
                </Text>
              </View>
            }
          />
        )}
      </View>
    </BottomSheet>
  );
};
BudgetDrillDownModal.displayName = 'BudgetDrillDownModal';

const styles = StyleSheet.create({
  emptyDrill: {
    marginTop: 80,
    alignItems: 'center',
    paddingHorizontal: 40,
  },
  spinnerMt: {
    marginTop: 40,
  },
  emptyText: {
    textAlign: 'center',
    marginTop: 12,
  },
});

import React from 'react';
import { View, Text, StyleSheet } from 'react-native';
import { format } from 'date-fns';

interface CalendarDaySummaryProps {
  selectedDate: Date;
  totalForDay: number;
  colors: any;
}

export const CalendarDaySummary: React.FC<CalendarDaySummaryProps> = ({
  selectedDate,
  totalForDay,
  colors,
}) => {
  return (
    <View style={styles.daySummary}>
      <Text style={[styles.summaryDate, { color: colors.text }]}>
        {format(selectedDate, 'EEE, MMM d, yyyy')}
      </Text>
      <Text
        style={[styles.summaryAmount, { color: totalForDay >= 0 ? colors.success : colors.danger }]}
      >
        {totalForDay >= 0 ? '+' : ''}₹{totalForDay.toLocaleString()}
      </Text>
    </View>
  );
};

const styles = StyleSheet.create({
  daySummary: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingHorizontal: 20,
    marginBottom: 12,
  },
  summaryDate: { fontSize: 15, fontWeight: 'bold' },
  summaryAmount: { fontSize: 16, fontWeight: 'bold' },
});

import React from 'react';
import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';
import { format, isSameDay } from 'date-fns';

interface CalendarGridProps {
  days: Date[];
  selectedDate: Date;
  setSelectedDate: (date: Date) => void;
  colors: any;
}

export const CalendarGrid: React.FC<CalendarGridProps> = ({
  days,
  selectedDate,
  setSelectedDate,
  colors,
}) => {
  return (
    <View style={styles.daysGrid}>
      {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((d) => (
        <Text key={d} style={[styles.dayLabel, { color: colors.textSecondary }]}>
          {d}
        </Text>
      ))}
      {days.map((day) => {
        const isSelected = isSameDay(day, selectedDate);
        return (
          <TouchableOpacity
            key={day.toISOString()}
            style={[
              styles.dayCell,
              isSelected && { backgroundColor: colors.primary, borderRadius: 12 },
            ]}
            onPress={() => setSelectedDate(day)}
          >
            <Text style={[styles.dayText, { color: isSelected ? '#fff' : colors.text }]}>
              {format(day, 'd')}
            </Text>
          </TouchableOpacity>
        );
      })}
    </View>
  );
};

const styles = StyleSheet.create({
  daysGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
  },
  dayLabel: {
    width: '14.28%',
    textAlign: 'center',
    fontSize: 12,
    fontWeight: '700',
    marginBottom: 12,
  },
  dayCell: {
    width: '14.28%',
    height: 40,
    justifyContent: 'center',
    alignItems: 'center',
    marginBottom: 4,
  },
  dayText: {
    fontSize: 14,
    fontWeight: '600',
  },
});

import React, { useState } from 'react';
import {
  Text,
  StyleSheet,
  TouchableOpacity,
  TextInput,
  ActivityIndicator,
  KeyboardAvoidingView,
  Platform,
  Keyboard,
} from 'react-native';
import { BottomSheet } from '../BottomSheet';
import { SegmentedControl } from '../SegmentedControl';
import { common } from '../../styles/common';

interface CategoryAddModalProps {
  visible: boolean;
  onClose: () => void;
  onAdd: (name: string, type: 'Expense' | 'Income', appIcon: string) => Promise<void>;
  colors: any;
}

export const CategoryAddModal: React.FC<CategoryAddModalProps> = ({
  visible,
  onClose,
  onAdd,
  colors,
}) => {
  const [name, setName] = useState('');
  const [appIcon, setAppIcon] = useState('');
  const [type, setType] = useState<'Expense' | 'Income'>('Expense');
  const [isSaving, setIsSaving] = useState(false);

  const handleSave = async () => {
    if (!name.trim()) return;
    Keyboard.dismiss();
    setIsSaving(true);
    try {
      await onAdd(name, type, appIcon);
      setName('');
      setAppIcon('');
      onClose();
    } catch (error) {
      console.error('Add category error:', error);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <BottomSheet visible={visible} onClose={onClose} title="New Category">
      <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : undefined}>
        <SegmentedControl
          options={[
            { label: 'Expense', value: 'Expense', activeColor: colors.danger },
            { label: 'Income', value: 'Income', activeColor: colors.success },
          ]}
          selectedValue={type}
          onValueChange={(val: 'Expense' | 'Income') => setType(val)}
          variant="small"
          containerStyle={common.mb20}
        />

        <Text style={[styles.inputLabel, { color: colors.textSecondary }]}>Category Name</Text>
        <TextInput
          style={[
            styles.inputField,
            { backgroundColor: colors.background, color: colors.text, borderColor: colors.border },
          ]}
          placeholder="e.g. Groceries"
          placeholderTextColor={colors.textSecondary}
          value={name}
          onChangeText={setName}
        />

        <Text style={[styles.inputLabel, { color: colors.textSecondary, marginTop: 16 }]}>
          Material Icon Name (Optional)
        </Text>
        <TextInput
          style={[
            styles.inputField,
            { backgroundColor: colors.background, color: colors.text, borderColor: colors.border },
          ]}
          placeholder="e.g. fastfood, flight"
          placeholderTextColor={colors.textSecondary}
          value={appIcon}
          onChangeText={setAppIcon}
          autoCapitalize="none"
        />

        <TouchableOpacity
          style={[
            styles.saveButton,
            { backgroundColor: colors.primary, opacity: !name.trim() || isSaving ? 0.5 : 1 },
          ]}
          onPress={handleSave}
          disabled={!name.trim() || isSaving}
        >
          {isSaving ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.saveButtonText}>Save Category</Text>
          )}
        </TouchableOpacity>
      </KeyboardAvoidingView>
    </BottomSheet>
  );
};

