interface DashboardSyncModalProps {
  visible: boolean;
  onClose: () => void;
  syncError: string | null;
  syncStatus: string;
  onRetry: () => void;
  colors: any;
}

export const DashboardSyncModal = React.memo(
  ({
    visible,
    onClose,
    syncError,
    syncStatus,
    onRetry,
    colors,
  }: DashboardSyncModalProps) => {
    const steps = [
      'Pushing local changes...',
      'Syncing Transactions',
      'Syncing Budgets',
      'Syncing Goals',
      'Calculating reports',
      'Finalizing',
    ];

    return (
      <BottomSheet
        visible={visible}
        onClose={onClose}
        title="Initializing JayLedger"
        subtitle={syncError ? 'Action Required' : 'Setting up your personal finance workspace...'}
        showCloseButton={!!syncError}
      >
        <View style={common.pb20}>
          <View style={styles.syncProgressContainer}>
            {syncError ? (
              <View style={styles.errorContainer}>
                <View style={styles.syncIconContainer}>
                  <MaterialIcons name="error-outline" size={60} color={colors.danger} />
                </View>
                <Text style={[styles.errorText, { color: colors.danger }]}>{syncError}</Text>
                <TouchableOpacity
                  style={[styles.retryBtn, { backgroundColor: colors.primary }]}
                  onPress={onRetry}
                >
                  <Text style={styles.retryBtnText}>Connect & Retry</Text>
                </TouchableOpacity>
              </View>
            ) : (
              <View style={styles.stepsContainer}>
                <View style={[styles.syncIconContainer, { alignSelf: 'center' }]}>
                  <MaterialIcons name="cloud-sync" size={60} color={colors.primary} />
                </View>
                {steps.map((step) => {
                  const isDone = steps.indexOf(step) < steps.indexOf(syncStatus);
                  const isActive = syncStatus === step;

                  return (
                    <View key={step} style={styles.stepRow}>
                      <View
                        style={[
                          styles.stepIndicator,
                          {
                            backgroundColor: isDone
                              ? colors.success
                              : isActive
                                ? colors.primary
                                : colors.border,
                          },
                        ]}
                      >
                        {isDone ? (
                          <MaterialIcons name="check" size={12} color="#fff" />
                        ) : isActive ? (
                          <ActivityIndicator size="small" color="#fff" />
                        ) : null}
                      </View>
                      <Text
                        style={[
                          styles.stepText,
                          {
                            color: isDone
                              ? colors.text
                              : isActive
                                ? colors.primary
                                : colors.textSecondary,
                          },
                        ]}
                      >
                        {step}
                      </Text>
                    </View>
                  );
                })}
              </View>
            )}
          </View>

          {!syncError && (
            <View style={styles.spinnerContainer}>
              <ActivityIndicator size="small" color={colors.primary} />
              <Text style={[styles.syncSubMessage, { color: colors.textSecondary }]}>
                This may take a minute...
              </Text>
            </View>
          )}
        </View>
      </BottomSheet>
    );
  },
);
DashboardSyncModal.displayName = 'DashboardSyncModal';

