import React, { useEffect, useState, useCallback, useMemo, useRef } from 'react';
import {
  View,
  Text,
  StyleSheet,
  FlatList,
  TouchableOpacity,
  ActivityIndicator,
  Platform,
  DeviceEventEmitter,
} from 'react-native';
import { useTheme } from '../store/ThemeContext';
import { useAuth } from '../store/AuthContext';
import { useToast } from '../store/ToastContext';
import {
  addBudget,
  updateBudget,
  deleteBudget,
  getCategories,
  getMinTransactionDate,
} from '../db/queries';
import { Budget, Transaction, Category } from '../models/types';
import { useNavigation } from '@react-navigation/native';
import MaterialIcons from '@expo/vector-icons/MaterialIcons';
import {
  format,
  startOfMonth,
  endOfMonth,
  isSameMonth,
  differenceInDays,
  getDaysInMonth,
  addMonths,
  subMonths,
} from 'date-fns';
import { BudgetCard } from '../components/BudgetCard';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { getRelativeTime } from '../utils/dateUtils';
import {
  fetchBudgetsWithSpending,
  fetchBudgetDrillDown,
  handleBudgetSync,
  EnrichedBudget,
} from '../services/budgetService';

// Modular Components
import { BudgetHeader } from '../components/budgets/BudgetHeader';
import { BudgetSortModal } from '../components/budgets/BudgetSortModal';
import { BudgetDeleteModal } from '../components/budgets/BudgetDeleteModal';
import { BudgetDrillDownModal } from '../components/budgets/BudgetDrillDownModal';
import { BudgetAddEditModal } from '../components/budgets/BudgetAddEditModal';
import { FloatingActionButton } from '../components/FloatingActionButton';
import { common } from '../styles/common';

const currentYearNum = new Date().getFullYear();

export default function BudgetsScreen() {
  const { colors } = useTheme();
  const { session } = useAuth();
  const navigation = useNavigation<any>();
  const { showToast } = useToast();

  const [data, setData] = useState<EnrichedBudget[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [minDate, setMinDate] = useState<Date>(new Date(currentYearNum, 0, 1));
  const maxDate = useMemo(() => endOfMonth(new Date()), []);
  const [lastSyncTime, setLastSyncTime] = useState<string>('');
  const listRef = useRef<FlatList>(null);

  const [sortBy, setSortBy] = useState<'name' | 'amount' | 'spent' | 'remaining'>('name');
  const [sortAsc, setSortAsc] = useState(true);
  const [showSortModal, setShowSortModal] = useState(false);

  // Add/Edit State
  const [showAddEdit, setShowAddEdit] = useState(false);
  const [editingBudget, setEditingBudget] = useState<Budget | null>(null);
  const [allCategories, setAllCategories] = useState<Category[]>([]);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  const [selectedDate, setSelectedDate] = useState(new Date());

  // Drill down state
  const [showDrillDown, setShowDrillDown] = useState(false);
  const [drillDownData, setDrillDownData] = useState<Transaction[]>([]);
  const [drillDownTitle, setDrillDownTitle] = useState('');
  const [drillDownLoading, setDrillDownLoading] = useState(false);

  const scrollToTop = useCallback(() => {
    listRef.current?.scrollToOffset({ offset: 0, animated: true });
  }, []);

  const monthStart = useMemo(() => startOfMonth(selectedDate), [selectedDate]);
  const monthEnd = useMemo(() => endOfMonth(selectedDate), [selectedDate]);
  const startDateStr = format(monthStart, 'yyyy-MM-dd');
  const endDateStr = format(monthEnd, 'yyyy-MM-dd');

  const isCurrentMonthSelected = useMemo(() => {
    return isSameMonth(selectedDate, new Date());
  }, [selectedDate]);

  const daysRemaining = useMemo(() => {
    if (!isCurrentMonthSelected) return 0;
    return differenceInDays(monthEnd, new Date()) + 1;
  }, [monthEnd, isCurrentMonthSelected]);

  const loadData = useCallback(async () => {
    if (!session?.user?.id) {
      setLoading(false);
      return;
    }
    setLoading(true);
    try {
      const sorted = await fetchBudgetsWithSpending(
        session.user.id,
        startDateStr,
        endDateStr,
        sortBy,
        sortAsc,
      );
      setData(sorted);

      const lastSync = await AsyncStorage.getItem(`@last_sync_budgets_${session.user.id}`);
      if (lastSync) setLastSyncTime(getRelativeTime(parseInt(lastSync)));

      if (sorted.length === 0) {
        const alreadyChecked = await AsyncStorage.getItem(
          `@initial_budget_sync_checked_${session.user.id}`,
        );
        if (!alreadyChecked) {
          setIsSyncing(true);
          await handleBudgetSync(session.user.id);
          const lastSyncUpdated = await AsyncStorage.getItem(
            `@last_sync_budgets_${session.user.id}`,
          );
          if (lastSyncUpdated) setLastSyncTime(getRelativeTime(parseInt(lastSyncUpdated)));
          const updated = await fetchBudgetsWithSpending(
            session.user.id,
            startDateStr,
            endDateStr,
            sortBy,
            sortAsc,
          );
          setData(updated);
          setIsSyncing(false);
        }
      }
    } catch (e) {
      console.error('Load Budgets Error:', e);
    } finally {
      setLoading(false);
    }
  }, [session, startDateStr, endDateStr, sortBy, sortAsc]);

  const handleManualSync = useCallback(async () => {
    if (!session?.user?.id || isSyncing) return;
    setIsSyncing(true);
    try {
      await handleBudgetSync(session.user.id);
      const lastSync = await AsyncStorage.getItem(`@last_sync_budgets_${session.user.id}`);
      if (lastSync) setLastSyncTime(getRelativeTime(parseInt(lastSync)));
      loadData();
      showToast('Budgets synced successfully', 'success');
    } catch (e) {
      console.error('Manual sync error:', e);
      showToast('Sync failed', 'error');
    } finally {
      setIsSyncing(false);
    }
  }, [session?.user?.id, isSyncing, loadData, showToast]);

  useEffect(() => {
    navigation.setOptions({
      headerTitle: () => (
        <TouchableOpacity
          activeOpacity={0.7}
          onPress={scrollToTop}
          style={styles.headerTitleContainer}
        >
          <Text style={[styles.headerTitle, { color: colors.text }]}>Budgets</Text>
          {lastSyncTime ? (
            <Text style={[styles.headerSubtitle, { color: colors.textSecondary }]}>
              Synced: {lastSyncTime}
            </Text>
          ) : null}
        </TouchableOpacity>
      ),
      headerTitleAlign: 'left',
      headerRight: () => (
        <TouchableOpacity
          onPress={handleManualSync}
          style={styles.headerRightBtn}
          disabled={isSyncing}
        >
          {isSyncing ? (
            <ActivityIndicator size="small" color={colors.primary} />
          ) : (
            <MaterialIcons name="refresh" size={24} color={colors.text} />
          )}
        </TouchableOpacity>
      ),
    });
  }, [
    navigation,
    isSyncing,
    colors.text,
    colors.textSecondary,
    colors.primary,
    lastSyncTime,
    handleManualSync,
    scrollToTop,
  ]);

  useEffect(() => {
    const timer = setTimeout(() => {
      loadData();
    }, 0);
    return () => clearTimeout(timer);
  }, [loadData]);

  useEffect(() => {
    const init = async () => {
      if (session?.user?.id) {
        const [cats, minD] = await Promise.all([
          getCategories(session.user.id),
          getMinTransactionDate(session.user.id),
        ]);
        setAllCategories(cats.filter((c) => c.type === 'Expense'));
        if (minD) setMinDate(new Date(minD));
      }
    };
    init();

    const subscription = DeviceEventEmitter.addListener('module_refreshed', () => {
      loadData();
    });

    return () => {
      subscription.remove();
    };
  }, [loadData, session]);

  const handleCardPress = async (budget: EnrichedBudget) => {
    if (!session?.user?.id) return;
    setDrillDownLoading(true);
    setDrillDownTitle(budget.name);
    setShowDrillDown(true);
    try {
      const transactions = await fetchBudgetDrillDown(
        session.user.id,
        budget.categories,
        startDateStr,
        endDateStr,
      );
      setDrillDownData(transactions);
    } catch (e) {
      console.error('Drill down error:', e);
    } finally {
      setDrillDownLoading(false);
    }
  };

  const { todayProgress, daysInMonth } = useMemo(() => {
    const today = new Date();
    const dim = getDaysInMonth(today);
    return { todayProgress: (today.getDate() / dim) * 100, daysInMonth: dim };
  }, []);

  return (
    <View style={[styles.container, { backgroundColor: colors.background }]}>
      <BudgetHeader
        selectedDate={selectedDate}
        minDate={minDate}
        maxDate={maxDate}
        sortBy={sortBy}
        sortAsc={sortAsc}
        onPrev={() => setSelectedDate(subMonths(selectedDate, 1))}
        onNext={() => setSelectedDate(addMonths(selectedDate, 1))}
        onYearMonthChange={setSelectedDate}
        onSortPress={() => setShowSortModal(true)}
      />

      <View style={styles.toolsRow}>
        {!isCurrentMonthSelected && (
          <TouchableOpacity
            onPress={() => setSelectedDate(new Date())}
            style={[styles.todayBtn, { backgroundColor: colors.primary + '15' }]}
          >
            <Text style={[styles.todayText, { color: colors.primary }]}>Back to Today</Text>
          </TouchableOpacity>
        )}
      </View>

      {loading && data.length === 0 ? (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color={colors.primary} />
        </View>
      ) : (
        <FlatList
          ref={listRef}
          data={data}
          keyExtractor={(item) => item.id}
          renderItem={({ item }) => (
            <BudgetCard
              name={item.name}
              amount={item.amount}
              spent={item.spent}
              startDateText={format(monthStart, 'MMM d')}
              endDateText={format(monthEnd, 'MMM d')}
              isCurrentMonth={isCurrentMonthSelected}
              daysRemaining={daysRemaining}
              todayProgress={todayProgress}
              daysInMonth={daysInMonth}
              onPress={() => handleCardPress(item)}
              onLongPress={() => {
                setEditingBudget(item);
                setShowAddEdit(true);
              }}
            />
          )}
          contentContainerStyle={common.pb40}
          ListEmptyComponent={
            <View style={styles.emptyContainer}>
              <MaterialIcons name="account-balance-wallet" size={64} color={colors.border} />
              <Text style={[styles.emptyText, { color: colors.textSecondary }]}>
                No Budgets Found
              </Text>
            </View>
          }
        />
      )}

      <BudgetSortModal
        visible={showSortModal}
        onClose={() => setShowSortModal(false)}
        sortBy={sortBy}
        sortAsc={sortAsc}
        onSortChange={(mode, asc) => {
          setSortBy(mode);
          setSortAsc(asc);
        }}
      />

      <BudgetDrillDownModal
        visible={showDrillDown}
        onClose={() => setShowDrillDown(false)}
        title={drillDownTitle}
        subtitle={format(selectedDate, 'MMMM yyyy')}
        loading={drillDownLoading}
        transactions={drillDownData}
      />

      <BudgetAddEditModal
        visible={showAddEdit}
        onClose={() => setShowAddEdit(false)}
        editingBudget={editingBudget}
        allCategories={allCategories}
        onDeleteRequest={setDeleteConfirmId}
        onSave={async (budgetData) => {
          if (!session?.user?.id) return;
          const finalData = { ...budgetData, user_id: session.user.id };
          if (editingBudget) await updateBudget(editingBudget.id, finalData);
          else await addBudget(finalData);
          setShowAddEdit(false);
          loadData();
          showToast(`Budget ${editingBudget ? 'updated' : 'added'} successfully`, 'success');
        }}
      />

      <BudgetDeleteModal
        visible={!!deleteConfirmId}
        onClose={() => setDeleteConfirmId(null)}
        onConfirm={async () => {
          if (deleteConfirmId) {
            await deleteBudget(deleteConfirmId);
            setDeleteConfirmId(null);
            setShowAddEdit(false);
            loadData();
            showToast('Budget deleted', 'success');
          }
        }}
      />

      <FloatingActionButton
        onPress={() => {
          setEditingBudget(null);
          setShowAddEdit(true);
        }}
        iconName="add"
        backgroundColor={colors.primary}
        style={styles.fab}
        iconSize={32}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  toolsRow: {
    padding: 16,
    flexDirection: 'row',
    justifyContent: 'flex-end',
    alignItems: 'center',
  },
  todayBtn: {
    paddingHorizontal: 15,
    paddingVertical: 8,
    borderRadius: 20,
  },
  todayText: {
    fontSize: 12,
    fontWeight: '700',
  },
  loadingContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  emptyContainer: {
    marginTop: 100,
    alignItems: 'center',
    justifyContent: 'center',
  },
  emptyText: {
    marginTop: 15,
    fontSize: 16,
    fontWeight: '600',
  },
  headerTitleContainer: {
    alignItems: 'flex-start',
  },
  headerTitle: {
    fontSize: 17,
    fontWeight: '700',
  },
  headerSubtitle: {
    fontSize: 10,
  },
  headerRightBtn: {
    paddingRight: 16,
    justifyContent: 'center',
    alignItems: 'center',
  },
  fab: {
    bottom: Platform.OS === 'ios' ? 40 : 24,
  },
});

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import {
  View,
  Text,
  StyleSheet,
  ActivityIndicator,
  TouchableOpacity,
  FlatList,
} from 'react-native';
import { useTheme } from '../store/ThemeContext';
import { useAuth } from '../store/AuthContext';
import { Category } from '../models/types';
import MaterialIcons from '@expo/vector-icons/MaterialIcons';
import { useNavigation } from '@react-navigation/native';
import { SegmentedControl } from '../components/SegmentedControl';
import { SearchBar } from '../components/SearchBar';
import { useToast } from '../store/ToastContext';

import {
  fetchCategoriesData,
  saveCategoryViewMode,
  addCategory,
  performCategorySync,
} from '../services/categoryService';

// Modular Components
import { CategoryCard } from '../components/categories/CategoryCard';
import { CategoryAddModal } from '../components/categories/CategoryAddModal';
import { FloatingActionButton } from '../components/FloatingActionButton';
import { common } from '../styles/common';

export default function CategoriesScreen() {
  const { colors } = useTheme();
  const { session } = useAuth();
  const user = session?.user;
  const { showToast } = useToast();
  const navigation = useNavigation<any>();

  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [syncing, setSyncing] = useState(false);

  const [viewMode, setViewMode] = useState<'list' | 'grid'>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const [sortAsc, setSortAsc] = useState(true);
  const [activeTab, setActiveTab] = useState<'Expense' | 'Income'>('Expense');

  const [isAddModalVisible, setAddModalVisible] = useState(false);

  const listRef = useRef<FlatList>(null);

  const scrollToTop = useCallback(() => {
    listRef.current?.scrollToOffset({ offset: 0, animated: true });
  }, []);

  const loadData = useCallback(async () => {
    if (!user?.id) return;
    setLoading(true);
    try {
      const { categories: fetchedCats, viewMode: savedMode } = await fetchCategoriesData(user.id);
      setCategories(fetchedCats);
      setViewMode(savedMode);

      // We still handle the initial sync check locally for now as it involves multiple AsyncStorage checks
      // but the core data loading is via service.
    } catch (err) {
      console.error('[Categories] loadData error:', err);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => {
    const timer = setTimeout(() => {
      loadData();
    }, 0);
    return () => clearTimeout(timer);
  }, [loadData]);

  const toggleViewMode = async () => {
    const newMode = viewMode === 'list' ? 'grid' : 'list';
    setViewMode(newMode);
    if (user?.id) {
      await saveCategoryViewMode(user.id, newMode);
    }
  };

  const handleManualSync = useCallback(async () => {
    if (!user?.id) return;
    setSyncing(true);
    try {
      const updatedCats = await performCategorySync(user.id);
      setCategories(updatedCats);
      showToast('Categories synced successfully', 'success');
    } catch (e) {
      console.error('Sync error:', e);
    } finally {
      setSyncing(false);
    }
  }, [user, showToast]);

  useEffect(() => {
    const timer = setTimeout(() => {
      navigation.setOptions({
        headerTitle: () => (
          <TouchableOpacity
            activeOpacity={0.7}
            onPress={scrollToTop}
            style={styles.headerTitleContainer}
          >
            <Text style={[styles.headerTitle, { color: colors.text }]}>Categories</Text>
          </TouchableOpacity>
        ),
        headerTitleAlign: 'left',
        headerRight: () => (
          <TouchableOpacity
            style={styles.headerRightBtn}
            onPress={handleManualSync}
            disabled={syncing}
            hitSlop={{ top: 15, bottom: 15, left: 15, right: 15 }}
          >
            {syncing ? (
              <ActivityIndicator size="small" color={colors.primary} />
            ) : (
              <MaterialIcons name="refresh" size={24} color={colors.text} />
            )}
          </TouchableOpacity>
        ),
      });
    }, 0);
    return () => clearTimeout(timer);
  }, [navigation, handleManualSync, syncing, colors.text, colors.primary, scrollToTop]);

  const handleAddCategorySubmit = async (
    name: string,
    type: 'Expense' | 'Income',
    appIcon: string,
  ) => {
    if (!user?.id) return;
    const newCat = await addCategory(user.id, name, type, appIcon);
    setCategories((prev) => [...prev, newCat]);
    showToast('Category added successfully', 'success');
  };

  const filteredData = useMemo(() => {
    let result = categories.filter((c) => c.type === activeTab);
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      result = result.filter((c) => c.name.toLowerCase().includes(q));
    }
    result.sort((a, b) => {
      const cmp = a.name.localeCompare(b.name);
      return sortAsc ? cmp : -cmp;
    });
    return result;
  }, [categories, searchQuery, sortAsc, activeTab]);

  if (loading) {
    return (
      <View style={[styles.centered, { backgroundColor: colors.background }]}>
        <ActivityIndicator color={colors.primary} size="large" />
      </View>
    );
  }

  return (
    <View style={[styles.container, { backgroundColor: colors.background }]}>
      <View style={styles.headerTools}>
        <SegmentedControl
          options={[
            { label: 'Expense', value: 'Expense', activeColor: colors.danger },
            { label: 'Income', value: 'Income', activeColor: colors.success },
          ]}
          selectedValue={activeTab}
          onValueChange={(val: 'Expense' | 'Income') => setActiveTab(val)}
          variant="medium"
          containerStyle={common.mb16}
        />

        <View style={styles.headerControls}>
          <SearchBar
            value={searchQuery}
            onChangeText={setSearchQuery}
            placeholder={`Search ${activeTab.toLowerCase()}...`}
            size="medium"
            containerStyle={common.flex1}
          />
          <View style={styles.actionRow}>
            <TouchableOpacity
              style={[
                styles.sortButton,
                { backgroundColor: colors.card, borderColor: colors.border },
              ]}
              onPress={() => setSortAsc(!sortAsc)}
            >
              <View style={common.flexRowCenterGap4}>
                <MaterialIcons name="sort" size={18} color={colors.primary} />
                <MaterialIcons
                  name={sortAsc ? 'arrow-upward' : 'arrow-downward'}
                  size={14}
                  color={colors.primary}
                />
              </View>
            </TouchableOpacity>
            <TouchableOpacity
              style={[styles.iconBtn, { backgroundColor: colors.card, borderColor: colors.border }]}
              onPress={toggleViewMode}
            >
              <MaterialIcons
                name={viewMode === 'list' ? 'grid-view' : 'view-list'}
                size={22}
                color={colors.text}
              />
            </TouchableOpacity>
          </View>
        </View>

        <View style={styles.captionRow}>
          <Text style={[styles.sortCaption, { color: colors.textSecondary }]}>Sorted by Name</Text>
        </View>
      </View>

      {filteredData.length === 0 ? (
        <View style={styles.emptyCentered}>
          <MaterialIcons name="storefront" size={64} color={colors.border} />
          <Text style={[styles.emptyHeader, { color: colors.textSecondary }]}>
            {searchQuery ? 'No Categories Found' : `No ${activeTab} Categories`}
          </Text>
          <Text style={[styles.emptySub, { color: colors.textSecondary }]}>
            {searchQuery ? `Nothing matches "${searchQuery}".` : 'Add your first category!'}
          </Text>
          {searchQuery && (
            <TouchableOpacity
              style={[styles.clearSearchBtn, { borderColor: colors.border }]}
              onPress={() => setSearchQuery('')}
            >
              <Text style={[styles.clearSearchText, { color: colors.primary }]}>Clear Search</Text>
            </TouchableOpacity>
          )}
        </View>
      ) : (
        <FlatList
          ref={listRef}
          key={viewMode}
          data={filteredData}
          numColumns={viewMode === 'grid' ? 3 : 1}
          keyExtractor={(item) => item.id}
          renderItem={({ item }) => (
            <CategoryCard
              item={item}
              viewMode={viewMode}
              colors={colors}
              onPress={(cat) =>
                navigation.navigate('Main', {
                  screen: 'Transactions',
                  params: { initialSelectedCats: [cat.id] },
                })
              }
            />
          )}
          contentContainerStyle={styles.listContent}
          columnWrapperStyle={viewMode === 'grid' ? styles.gridWrapper : undefined}
          showsVerticalScrollIndicator={false}
        />
      )}

      <FloatingActionButton
        onPress={() => setAddModalVisible(true)}
        iconName="add"
        backgroundColor={colors.primary}
      />

      <CategoryAddModal
        visible={isAddModalVisible}
        onClose={() => setAddModalVisible(false)}
        onAdd={handleAddCategorySubmit}
        colors={colors}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  centered: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  emptyCentered: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    padding: 24,
    marginTop: 60,
  },
  headerTools: { padding: 16, paddingTop: 8, zIndex: 10 },
