const SettingRow = ({
  icon,
  title,
  value,
  onPress,
  showArrow = true,
  color,
  isLoading,
}: {
  icon: keyof typeof Icon.glyphMap;
  title: string;
  value?: string;
  onPress?: () => void;
  showArrow?: boolean;
  color?: string;
  isLoading?: boolean;
}) => {
